1	<?php
2	namespace App\Http\Requests;
3	
4	use Illuminate\Foundation\Http\FormRequest;
5	
6	class CreateReservationRequestForm extends FormRequest
7	{
8	    public function authorize(): bool { return true; }
9	
10	    public function rules(): array
11	    {
12	        $rules = [
13	            'resource_id' => 'required|exists:resources,id',
14	            'reservation_type' => 'required|in:equipment,venue',
15	            'notes' => 'nullable|string|max:1000',
16	            'idempotency_key' => 'required|string|max:255',
17	            'class_id' => 'nullable|exists:classes,id',
18	            'assignment_id' => 'nullable|exists:assignments,id',
19	        ];
20	
21	        if ($this->input('reservation_type') === 'venue') {
22	            $rules['venue_id'] = 'required|exists:venues,id';
23	            $rules['venue_time_slot_id'] = 'required|exists:venue_time_slots,id';
24	            // start_date/end_date derived from the slot
25	        } else {
26	            $rules['start_date'] = 'required|date';
27	            $rules['end_date'] = 'required|date|after_or_equal:start_date';
28	        }
29	
30	        return $rules;
31	    }
32	}
