2	namespace App\Http\Controllers\Api;
3	
4	use App\Http\Controllers\Controller;
5	use App\Domain\Lending\LendingService;
6	use App\Models\LoanRequest;
7	use App\Models\Checkout;
8	use App\Http\Requests\CreateLoanRequest;
9	use App\Http\Requests\ApproveLoanRequestForm;
10	use App\Http\Resources\LoanRequestResource;
11	use App\Http\Resources\CheckoutResource;
12	use Illuminate\Http\Request;
13	
14	class LoanController extends Controller
15	{
16	    public function __construct(protected LendingService $lending) {}
17	
18	    public function index(Request $request)
19	    {
20	        $query = LoanRequest::with(['user', 'resource', 'approval', 'checkout']);
21	        $user = $request->user();
22	
23	        if ($user->isStudent()) {
24	            $query->where('user_id', $user->id);
25	        } elseif (!$user->isAdmin()) {
26	            // Teachers/TAs: only loans within their scoped classes/assignments/courses
27	            $hasFullScope = $user->permissionScopes()->where('scope_type', 'full')->exists();
28	
29	            if (!$hasFullScope) {
30	                $scopedClassIds = $user->permissionScopes()->whereNotNull('class_id')->pluck('class_id');
31	                $scopedAssignmentIds = $user->permissionScopes()->whereNotNull('assignment_id')->pluck('assignment_id');
32	                // Resolve course scopes to their class IDs
33	                $scopedCourseIds = $user->permissionScopes()->whereNotNull('course_id')->pluck('course_id');
34	                $courseClassIds = \App\Models\ClassModel::whereIn('course_id', $scopedCourseIds)->pluck('id');
35	                $allClassIds = $scopedClassIds->merge($courseClassIds)->unique();
36	
37	                $query->where(function ($q) use ($allClassIds, $scopedAssignmentIds) {
38	                    $q->whereIn('class_id', $allClassIds)
39	                      ->orWhereIn('assignment_id', $scopedAssignmentIds);
40	                });
41	            }
42	        }
43	
44	        if ($request->filled('status')) $query->where('status', $request->status);
45	
46	        if ($request->filled('search')) {
47	            $search = $request->search;
48	            $query->whereHas('user', fn($q) => $q->where('display_name', 'like', "%{$search}%")->orWhere('username', 'like', "%{$search}%"));
49	        }
50	
51	        return LoanRequestResource::collection($query->latest()->paginate(20));
52	    }
53	
54	    public function store(CreateLoanRequest $request)
55	    {
56	        if (!$request->user()->isStudent()) {
57	            return response()->json(['error' => 'Only students can submit loan requests.'], 403);
58	        }
59	        $loan = $this->lending->createLoanRequest($request->user(), $request->validated());
60	        return (new LoanRequestResource($loan))->response()->setStatusCode(201);
61	    }
62	
63	    public function show(LoanRequest $loan)
64	    {
65	        $this->authorize('view', $loan);
66	        return new LoanRequestResource($loan->load(['user', 'resource', 'approval', 'checkout.checkin', 'checkout.renewals']));
67	    }
68	
69	    public function approve(ApproveLoanRequestForm $request, LoanRequest $loan)
70	    {
71	        $this->authorize('approve', $loan);
72	        $loan = $this->lending->approveLoanRequest($loan, $request->user(), $request->status, $request->reason);
73	        return new LoanRequestResource($loan);
74	    }
75	
76	    public function checkout(Request $request, LoanRequest $loan)
77	    {
78	        $this->authorize('checkout', $loan);
79	        $checkout = $this->lending->checkout($loan, $request->user());
80	        return (new CheckoutResource($checkout))->response()->setStatusCode(201);
81	    }
82	
83	    public function checkin(Request $request, Checkout $checkout)
84	    {
85	        $this->authorize('checkin', $checkout);
86	        $checkin = $this->lending->checkin($checkout, $request->user(), $request->condition, $request->notes);
87	        return response()->json(['message' => 'Check-in completed.', 'checkin_id' => $checkin->id]);
88	    }
89	
90	    public function renew(Request $request, Checkout $checkout)
91	    {
92	        $this->authorize('renew', $checkout);
93	        $renewal = $this->lending->renew($checkout, $request->user());
94	        return response()->json(['message' => 'Renewed.', 'new_due_date' => $renewal->new_due_date]);
95	    }
96	
97	    public function checkoutsList(Request $request)
98	    {
99	        $user = $request->user();
100	
101	        // Students cannot access the checkouts list
102	        if ($user->isStudent()) {
103	            return response()->json(['error' => 'Unauthorized.'], 403);
104	        }
105	
106	        $query = Checkout::with(['loanRequest.resource', 'loanRequest.user', 'checkedOutTo', 'checkedOutBy']);
107	
108	        // Scope for non-admin staff
109	        if (!$user->isAdmin()) {
110	            $hasFullScope = $user->permissionScopes()->where('scope_type', 'full')->exists();
111	
112	            if (!$hasFullScope) {
113	                $scopedClassIds = $user->permissionScopes()->whereNotNull('class_id')->pluck('class_id');
114	                $scopedAssignmentIds = $user->permissionScopes()->whereNotNull('assignment_id')->pluck('assignment_id');
115	                $scopedCourseIds = $user->permissionScopes()->whereNotNull('course_id')->pluck('course_id');
116	                $courseClassIds = \App\Models\ClassModel::whereIn('course_id', $scopedCourseIds)->pluck('id');
117	                $allClassIds = $scopedClassIds->merge($courseClassIds)->unique();
118	
119	                $query->whereHas('loanRequest', function ($q) use ($allClassIds, $scopedAssignmentIds) {
120	                    $q->whereIn('class_id', $allClassIds)
121	                      ->orWhereIn('assignment_id', $scopedAssignmentIds);
122	                });
123	            }
124	        }
125	
126	        if ($request->filled('status')) {
127	            if ($request->status === 'active') {
128	                $query->whereNull('returned_at');
129	            }
130	        }
131	
132	        if ($request->filled('search')) {
133	            $search = $request->search;
134	            $query->whereHas('checkedOutTo', fn($q) => $q->where('display_name', 'like', "%{$search}%")->orWhere('username', 'like', "%{$search}%"));
135	        }
136	
137	        return CheckoutResource::collection($query->latest()->paginate(20));
138	    }
139	}
