3	namespace Tests\Feature\Api;
4	
5	use Tests\TestCase;
6	use App\Models\{LoanRequest, ReservationRequest, Hold, PermissionScope, Department};
7	use Illuminate\Foundation\Testing\RefreshDatabase;
8	use Tests\Support\TestHelpers;
9	
10	class UIContractTest extends TestCase
11	{
12	    use RefreshDatabase, TestHelpers;
13	
14	    // =========================================================================
15	    // 1. Loan with class_id is visible to scoped teacher
16	    // =========================================================================
17	
18	    public function test_loan_with_class_id_visible_to_scoped_teacher(): void
19	    {
20	        $structure = $this->createCourseStructure();
21	        $teacher = $this->createTeacher();
22	        PermissionScope::create(['user_id' => $teacher->id, 'class_id' => $structure['class']->id, 'scope_type' => 'class']);
23	
24	        $student = $this->createStudent();
25	        $this->assignMembership($student);
26	        PermissionScope::create(['user_id' => $student->id, 'class_id' => $structure['class']->id, 'scope_type' => 'class']);
27	        [$resource, $lot] = $this->createResourceWithLot();
28	
29	        // Student creates loan WITH class_id
30	        $key = 'class-loan-1';
31	        $this->actingAs($student)->postJson('/api/loans', [
32	            'resource_id' => $resource->id,
33	            'quantity' => 1,
34	            'idempotency_key' => $key,
35	            'class_id' => $structure['class']->id,
36	        ], ['X-Idempotency-Key' => $key])->assertCreated();
37	
38	        // Teacher sees it in their scoped list
39	        $response = $this->actingAs($teacher)->getJson('/api/loans?status=pending');
40	        $this->assertGreaterThanOrEqual(1, count($response->json('data')));
41	    }
42	
43	    public function test_loan_without_class_id_not_visible_to_class_scoped_teacher(): void
44	    {
45	        $structure = $this->createCourseStructure();
46	        $teacher = $this->createTeacher();
47	        PermissionScope::create(['user_id' => $teacher->id, 'class_id' => $structure['class']->id, 'scope_type' => 'class']);
48	
49	        $student = $this->createStudent();
50	        $this->assignMembership($student);
51	        [$resource, $lot] = $this->createResourceWithLot();
52	
53	        // Loan without class_id
54	        LoanRequest::create([
55	            'user_id' => $student->id, 'resource_id' => $resource->id, 'inventory_lot_id' => $lot->id,
56	            'quantity' => 1, 'status' => 'pending', 'requested_at' => now(), 'idempotency_key' => uniqid(),
57	        ]);
58	
59	        // Teacher should NOT see it (no class_id match)
60	        $response = $this->actingAs($teacher)->getJson('/api/loans');
61	        $this->assertEquals(0, count($response->json('data')));
62	    }
63	
64	    // =========================================================================
65	    // 2. Reservation approval via API
66	    // =========================================================================
67	
68	    public function test_staff_can_approve_reservation_via_api(): void
69	    {
70	        $structure = $this->createCourseStructure();
71	        $teacher = $this->createTeacher();
72	        $this->grantScope($teacher);
73	
74	        $student = $this->createStudent();
75	        [$resource, $lot] = $this->createResourceWithLot();
76	
77	        $reservation = ReservationRequest::create([
78	            'user_id' => $student->id, 'resource_id' => $resource->id,
79	            'reservation_type' => 'equipment', 'status' => 'pending',
80	            'start_date' => now()->addDay(), 'end_date' => now()->addDays(5),
81	            'idempotency_key' => uniqid(),
82	        ]);
83	
84	        $key = 'approve-res-ui-1';
85	        $response = $this->actingAs($teacher)->postJson("/api/reservations/{$reservation->id}/approve", [
86	            'status' => 'approved',
87	        ], ['X-Idempotency-Key' => $key]);
88	
89	        $response->assertOk();
90	        $this->assertEquals('approved', $reservation->fresh()->status);
91	    }
92	
93	    // =========================================================================
94	    // 3. Hold creation with valid hold_type
95	    // =========================================================================
96	
97	    public function test_admin_can_create_manual_hold(): void
98	    {
99	        $admin = $this->createAdmin();
100	        $this->grantScope($admin);
101	        $student = $this->createStudent();
102	
103	        $key = 'hold-manual-1';
104	        $response = $this->actingAs($admin)->postJson('/api/admin/holds', [
105	            'user_id' => $student->id,
106	            'hold_type' => 'manual',
107	            'reason' => 'Administrative review required',
108	        ], ['X-Idempotency-Key' => $key]);
109	
110	        $response->assertOk();
111	        $this->assertDatabaseHas('holds', [
112	            'user_id' => $student->id,
113	            'hold_type' => 'manual',
114	            'status' => 'active',
115	        ]);
116	    }
117	
118	    public function test_hold_creation_rejects_invalid_type(): void
119	    {
120	        $admin = $this->createAdmin();
121	        $this->grantScope($admin);
122	        $student = $this->createStudent();
123	
124	        $key = 'hold-invalid-1';
125	        $response = $this->actingAs($admin)->postJson('/api/admin/holds', [
126	            'user_id' => $student->id,
127	            'hold_type' => 'general', // not in manual,system
128	            'reason' => 'Test',
129	        ], ['X-Idempotency-Key' => $key]);
130	
131	        $response->assertUnprocessable();
132	    }
133	
134	    public function test_hold_list_returns_correct_fields(): void
135	    {
136	        $admin = $this->createAdmin();
137	        $this->grantScope($admin);
138	        $student = $this->createStudent();
139	
140	        Hold::create([
141	            'user_id' => $student->id,
142	            'hold_type' => 'manual',
143	            'reason' => 'Test hold',
144	            'status' => 'active',
145	            'triggered_at' => now(),
146	        ]);
147	
148	        $response = $this->actingAs($admin)->getJson('/api/admin/holds');
149	        $response->assertOk();
150	
151	        $holds = $response->json('data');
152	        $this->assertNotEmpty($holds);
153	        $hold = $holds[0];
154	        // Verify the response includes the correct field names
155	        $this->assertArrayHasKey('hold_type', $hold);
156	        $this->assertArrayHasKey('status', $hold);
157	        $this->assertArrayHasKey('triggered_at', $hold);
158	        $this->assertEquals('manual', $hold['hold_type']);
159	        $this->assertEquals('active', $hold['status']);
160	    }
161	
162	    // =========================================================================
163	    // 7. /my-classes endpoint
164	    // =========================================================================
165	
166	    public function test_my_classes_returns_enrolled_classes(): void
167	    {
168	        $student = $this->createStudent();
169	        $structure = $this->createCourseStructure();
170	        PermissionScope::create(['user_id' => $student->id, 'class_id' => $structure['class']->id, 'scope_type' => 'class']);
171	
172	        $response = $this->actingAs($student)->getJson('/api/my-classes');
173	        $response->assertOk();
174	        $classes = $response->json();
175	        $this->assertNotEmpty($classes);
176	        $this->assertEquals($structure['class']->id, $classes[0]['id']);
177	    }
178	
179	    public function test_my_classes_resolves_course_scopes(): void
180	    {
181	        $student = $this->createStudent();
182	        $structure = $this->createCourseStructure();
183	        // Scope to course, not class
184	        PermissionScope::create(['user_id' => $student->id, 'course_id' => $structure['course']->id, 'scope_type' => 'course']);
185	
186	        $response = $this->actingAs($student)->getJson('/api/my-classes');
187	        $response->assertOk();
188	        $classes = $response->json();
189	        $this->assertNotEmpty($classes);
190	    }
191	}
