2	namespace App\Http\Middleware;
3	
4	use Closure;
5	use App\Models\IdempotencyKey;
6	use Illuminate\Support\Facades\Log;
7	use Illuminate\Http\Request;
8	
9	class IdempotencyMiddleware
10	{
11	    public function handle(Request $request, Closure $next)
12	    {
13	        if (!in_array($request->method(), ['POST', 'PUT', 'PATCH', 'DELETE'])) {
14	            return $next($request);
15	        }
16	
17	        $key = $request->header('X-Idempotency-Key');
18	
19	        // Require idempotency key on all state-changing requests
20	        if (!$key) {
21	            // No exemptions — all state-changing requests require idempotency keys per prompt.
22	            return response()->json([
23	                'error' => 'X-Idempotency-Key header is required for state-changing requests.',
24	            ], 422);
25	        }
26	
27	        $userId = $request->user()?->id;
28	        $route = $request->path();
29	        $payloadHash = hash('sha256', json_encode($request->except(['_token'])));
30	
31	        // Scope lookup by user_id + route + key
32	        $existing = IdempotencyKey::where('key', $key)
33	            ->where('user_id', $userId)
34	            ->where('route', $route)
35	            ->first();
36	
37	        if ($existing) {
38	            if ($existing->payload_hash !== $payloadHash) {
39	                Log::channel('operations')->warning('Idempotency conflict', [
40	                    'key' => $key, 'user_id' => $userId, 'route' => $route,
41	                ]);
42	                return response()->json([
43	                    'error' => 'Idempotency key conflict: different payload for same key.',
44	                ], 409);
45	            }
46	            // Replay stored response
47	            return response()->json($existing->response_body, $existing->response_code);
48	        }
49	
50	        $response = $next($request);
51	
52	        try {
53	            // Never persist auth tokens in idempotency response snapshots
54	            $responseBody = json_decode($response->getContent(), true);
55	            if (str_starts_with($route, 'api/auth/')) {
56	                $responseBody = ['_replayed' => true, '_status' => $response->getStatusCode()];
57	            }
58	
59	            IdempotencyKey::create([
60	                'key' => $key,
61	                'user_id' => $userId,
62	                'route' => $route,
63	                'payload_hash' => $payloadHash,
64	                'response_code' => $response->getStatusCode(),
65	                'response_body' => $responseBody,
66	                'expires_at' => now()->addHours(24),
67	            ]);
68	        } catch (\Illuminate\Database\QueryException $e) {
69	            // Ignore duplicate key errors from race conditions
70	        }
71	
72	        return $response;
73	    }
74	}
