2	namespace App\Http\Controllers\Api;
3	
4	use App\Http\Controllers\Controller;
5	use App\Domain\Auth\AuthService;
6	use App\Http\Requests\LoginRequest;
7	use App\Http\Requests\ChangePasswordRequest;
8	use Illuminate\Http\JsonResponse;
9	use Illuminate\Http\Request;
10	
11	class AuthController extends Controller
12	{
13	    public function __construct(protected AuthService $authService) {}
14	
15	    public function login(LoginRequest $request): JsonResponse
16	    {
17	        $user = $this->authService->authenticate($request->username, $request->password);
18	        $user->load('roles', 'membership.tier');
19	        $token = $user->createToken('api-token')->plainTextToken;
20	
21	        return response()->json([
22	            'user' => new \App\Http\Resources\UserResource($user),
23	            'token' => $token,
24	            'force_password_change' => $user->force_password_change,
25	        ]);
26	    }
27	
28	    public function logout(Request $request): JsonResponse
29	    {
30	        $token = $request->user()->currentAccessToken();
31	        if (method_exists($token, 'delete')) {
32	            $token->delete();
33	        }
34	        return response()->json(['message' => 'Logged out.']);
35	    }
36	
37	    public function me(Request $request): JsonResponse
38	    {
39	        $user = $request->user()->load('roles', 'membership.tier');
40	
41	        // Active reminders: prefer persisted reminder_events (created by ProcessReminders job),
42	        // fall back to computed checkout count for real-time accuracy before the job runs.
43	        $persistedCount = \App\Models\ReminderEvent::where('user_id', $user->id)
44	            ->whereNull('acknowledged_at')
45	            ->whereIn('reminder_type', ['upcoming_due', 'overdue'])
46	            ->count();
47	
48	        $computedCount = \App\Models\Checkout::where('checked_out_to', $user->id)
49	            ->whereNull('returned_at')
50	            ->where('due_date', '<=', now()->addHours(48))
51	            ->count();
52	
53	        $dueSoonCount = max($persistedCount, $computedCount);
54	
55	        $resource = new \App\Http\Resources\UserResource($user);
56	
57	        return response()->json(array_merge(
58	            $resource->resolve($request),
59	            ['reminders_count' => $dueSoonCount]
60	        ));
61	    }
62	
63	    public function changePassword(ChangePasswordRequest $request): JsonResponse
64	    {
65	        if ($request->user()->force_password_change) {
66	            $this->authService->forcePasswordChange($request->user(), $request->new_password);
67	        } else {
68	            $this->authService->changePassword($request->user(), $request->current_password, $request->new_password);
69	        }
70	
71	        return response()->json(['message' => 'Password changed successfully.']);
72	    }
73	}
