2	namespace App\Http\Controllers\Api;
3	
4	use App\Http\Controllers\Controller;
5	use App\Domain\Files\FileService;
6	use App\Models\FileAsset;
7	use Illuminate\Http\Request;
8	
9	class FileController extends Controller
10	{
11	    public function __construct(protected FileService $fileService) {}
12	
13	    private const ALLOWED_ATTACHABLE_TYPES = [
14	        'loan_request' => \App\Models\LoanRequest::class,
15	        'reservation' => \App\Models\ReservationRequest::class,
16	        'resource' => \App\Models\Resource::class,
17	    ];
18	
19	    public function upload(Request $request)
20	    {
21	        $request->validate([
22	            'file' => 'required|file|max:10240|mimes:pdf,jpg,jpeg,png',
23	            'attachable_type' => 'nullable|string|in:loan_request,reservation,resource',
24	            'attachable_id' => 'nullable|integer',
25	        ]);
26	
27	        $attachableType = null;
28	        $attachableId = null;
29	
30	        if ($request->filled('attachable_type') && $request->filled('attachable_id')) {
31	            $attachableType = self::ALLOWED_ATTACHABLE_TYPES[$request->attachable_type] ?? null;
32	            if (!$attachableType) {
33	                return response()->json(['error' => 'Invalid attachable type.'], 422);
34	            }
35	            // Verify the target record exists
36	            if (!$attachableType::find($request->attachable_id)) {
37	                return response()->json(['error' => 'Attachable record not found.'], 422);
38	            }
39	            // Verify user has access to the attach target
40	            if ($attachableType === \App\Models\LoanRequest::class) {
41	                $loan = $attachableType::find($request->attachable_id);
42	                if ($loan && $loan->user_id !== $request->user()->id && !$request->user()->isAdmin()) {
43	                    return response()->json(['error' => 'You cannot attach files to another user\'s loan.'], 403);
44	                }
45	            } elseif ($attachableType === \App\Models\ReservationRequest::class) {
46	                $reservation = $attachableType::find($request->attachable_id);
47	                if ($reservation && $reservation->user_id !== $request->user()->id && !$request->user()->isAdmin()) {
48	                    return response()->json(['error' => 'You cannot attach files to another user\'s reservation.'], 403);
49	                }
50	            } elseif ($attachableType === \App\Models\Resource::class) {
51	                if ($request->user()->isStudent()) {
52	                    return response()->json(['error' => 'Students cannot attach files to resources.'], 403);
53	                }
54	                if (!$request->user()->isAdmin()) {
55	                    $resource = \App\Models\Resource::find($request->attachable_id);
56	                    if ($resource) {
57	                        $hasScope = $request->user()->permissionScopes()->where(function ($q) use ($resource) {
58	                            $q->where('scope_type', 'full')
59	                              ->orWhere('department_id', $resource->department_id);
60	                        })->exists();
61	                        if (!$hasScope) {
62	                            return response()->json(['error' => 'You do not have scope on this resource\'s department.'], 403);
63	                        }
64	                    }
65	                }
66	            }
67	            $attachableId = $request->attachable_id;
68	        }
69	
70	        $asset = $this->fileService->upload($request->file('file'), $request->user(), $attachableType, $attachableId);
71	        return response()->json(['message' => 'Uploaded.', 'file' => new \App\Http\Resources\FileAssetResource($asset)]);
72	    }
73	
74	    public function download(FileAsset $file, Request $request)
75	    {
76	        $this->authorize('download', $file);
77	        $path = $this->fileService->download($file, $request->user());
78	        return response()->download($path, $file->original_filename, ['Content-Type' => $file->mime_type]);
79	    }
80	
81	    public function index(Request $request)
82	    {
83	        $user = $request->user();
84	        $query = FileAsset::query();
85	
86	        if ($user->isStudent()) {
87	            // Students see only their own files
88	            $query->where('uploaded_by', $user->id);
89	        } elseif (!$user->isAdmin()) {
90	            // Staff see their own files + files attached to loan requests in their scope
91	            $hasFullScope = $user->permissionScopes()->where('scope_type', 'full')->exists();
92	            if (!$hasFullScope) {
93	                $scopedClassIds = $user->permissionScopes()->whereNotNull('class_id')->pluck('class_id');
94	                $scopedAssignmentIds = $user->permissionScopes()->whereNotNull('assignment_id')->pluck('assignment_id');
95	                // Resolve course scopes to class IDs
96	                $scopedCourseIds = $user->permissionScopes()->whereNotNull('course_id')->pluck('course_id');
97	                $courseClassIds = \App\Models\ClassModel::whereIn('course_id', $scopedCourseIds)->pluck('id');
98	                $scopedClassIds = $scopedClassIds->merge($courseClassIds)->unique();
99	
100	                $query->where(function ($q) use ($user, $scopedClassIds, $scopedAssignmentIds) {
101	                    $q->where('uploaded_by', $user->id)
102	                      ->orWhere(function ($inner) use ($scopedClassIds, $scopedAssignmentIds) {
103	                          $inner->where('attachable_type', \App\Models\LoanRequest::class)
104	                                ->whereIn('attachable_id', function ($sub) use ($scopedClassIds, $scopedAssignmentIds) {
105	                                    $sub->select('id')->from('loan_requests')
106	                                        ->where(function ($w) use ($scopedClassIds, $scopedAssignmentIds) {
107	                                            $w->whereIn('class_id', $scopedClassIds)
108	                                              ->orWhereIn('assignment_id', $scopedAssignmentIds);
109	                                        });
110	                                });
111	                      })
112	                      ->orWhere(function ($inner) use ($scopedClassIds, $scopedAssignmentIds) {
113	                          $inner->where('attachable_type', \App\Models\ReservationRequest::class)
114	                                ->whereIn('attachable_id', function ($sub) use ($scopedClassIds, $scopedAssignmentIds) {
115	                                    $sub->select('id')->from('reservation_requests')
116	                                        ->where(function ($w) use ($scopedClassIds, $scopedAssignmentIds) {
117	                                            $w->whereIn('class_id', $scopedClassIds)
118	                                              ->orWhereIn('assignment_id', $scopedAssignmentIds);
119	                                        });
120	                                });
121	                      });
122	                });
123	            }
124	        }
125	        // Admin sees all files (no filter)
126	
127	        return \App\Http\Resources\FileAssetResource::collection($query->latest()->paginate(20));
128	    }
129	}
