            'resource_id' => $resource->id, 'quantity' => 1, 'idempotency_key' => 'body-key-user2',
        ], $headers)->assertCreated();

        // Each user should have their own loan — header key is scoped by user
        $this->assertDatabaseCount('loan_requests', 2);
    }

