9	class ReservationService
10	{
11	    public function __construct(protected AvailabilityService $availability) {}
12	
13	    public function createReservation(User $user, array $data): ReservationRequest
14	    {
15	        return DB::transaction(function () use ($user, $data) {
16	            // Check allowlist/blacklist
17	            $resource = \App\Models\Resource::findOrFail($data['resource_id']);
18	            $accessCheck = $this->availability->checkUserResourceAccess($user, $resource);
19	            if (!$accessCheck['allowed']) {
20	                throw new \App\Common\Exceptions\BusinessRuleException($accessCheck['reason']);
21	            }
22	
23	            // Validate resource type matches reservation type
24	            if ($data['reservation_type'] === 'venue' && $resource->resource_type !== 'venue') {
25	                throw new \App\Common\Exceptions\BusinessRuleException('Venue reservations can only be made for venue resources.');
26	            }
27	            if ($data['reservation_type'] === 'equipment' && $resource->resource_type !== 'equipment') {
28	                throw new \App\Common\Exceptions\BusinessRuleException('Equipment reservations can only be made for equipment resources.');
29	            }
30	
31	            if ($data['reservation_type'] === 'venue') {
32	                // Verify the venue belongs to the claimed resource
33	                $venue = \App\Models\Venue::where('id', $data['venue_id'] ?? 0)
34	                    ->where('resource_id', $resource->id)
35	                    ->first();
36	
37	                if (!$venue) {
38	                    throw new \App\Common\Exceptions\BusinessRuleException('Venue does not belong to this resource.');
39	                }
40	
41	                $slot = VenueTimeSlot::where('id', $data['venue_time_slot_id'])
42	                    ->lockForUpdate()
43	                    ->firstOrFail();
44	
45	                if (!$slot->is_available) {
46	                    throw new \App\Common\Exceptions\BusinessRuleException('Time slot is not available.');
47	                }
48	
49	                if ($slot->reserved_by_reservation_id !== null) {
50	                    throw new \App\Common\Exceptions\BusinessRuleException(
51	                        'Time slot conflict: this slot is already reserved.'
52	                    );
53	                }
54	
55	                // Verify slot belongs to the validated venue
56	                if ($slot->venue_id !== $venue->id) {
57	                    throw new \App\Common\Exceptions\BusinessRuleException('Time slot does not belong to the requested venue.');
58	                }
59	
60	                // Derive dates from the slot
61	                $startDate = $slot->date;
62	                $endDate = $slot->date;
63	            } else {
64	                // Equipment reservation: check user limits
65	                $check = $this->availability->canUserBorrow($user);
66	                if (!$check['allowed']) {
67	                    throw new \App\Common\Exceptions\BusinessRuleException($check['reason']);
68	                }
69	                $startDate = $data['start_date'];
70	                $endDate = $data['end_date'];
71	
72	                // Check for overlapping equipment reservations
73	                if ($this->availability->checkEquipmentReservationOverlap(
74	                    $data['resource_id'], $data['start_date'], $data['end_date']
75	                )) {
76	                    throw new \App\Common\Exceptions\BusinessRuleException(
77	                        'Equipment reservation conflict: an existing reservation overlaps this date range.'
78	                    );
79	                }
80	            }
81	
82	            // Validate requester's claim to class/assignment
83	            $classId = $data['class_id'] ?? null;
84	            $assignmentId = $data['assignment_id'] ?? null;
85	
86	            // If assignment_id is provided, resolve and enforce consistency
87	            if ($assignmentId) {
88	                $assignment = \App\Models\Assignment::find($assignmentId);
89	                if (!$assignment) {
90	                    throw new \App\Common\Exceptions\BusinessRuleException('The specified assignment does not exist.');
91	                }
92	
93	                // Enforce internal consistency: assignment must belong to the claimed class
94	                if ($classId && $assignment->class_id !== (int) $classId) {
95	                    throw new \App\Common\Exceptions\BusinessRuleException('The assignment does not belong to the specified class.');
96	                }
97	
98	                // Auto-resolve class_id from the assignment if not provided
99	                if (!$classId) {
100	                    $classId = $assignment->class_id;
101	                    $data['class_id'] = $classId;
102	                }
103	
104	                // Student must have a scope covering this assignment's class or course
105	                $assignmentClassId = $assignment->class_id;
106	                $assignmentCourseId = \App\Models\ClassModel::where('id', $assignmentClassId)->value('course_id');
107	
108	                $ok = $user->permissionScopes()->where(function ($q) use ($assignmentClassId, $assignmentCourseId) {
109	                    $q->where('scope_type', 'full')
110	                      ->orWhere('class_id', $assignmentClassId);
111	                    if ($assignmentCourseId) {
112	                        $q->orWhere('course_id', $assignmentCourseId);
113	                    }
114	                })->exists();
115	
116	                if (!$ok) {
117	                    throw new \App\Common\Exceptions\BusinessRuleException('You do not have access to the specified assignment.');
118	                }
119	            }
120	
121	            if ($classId) {
122	                $ok = $user->permissionScopes()->where(function ($q) use ($classId) {
123	                    $q->where('class_id', $classId)->orWhere('scope_type', 'full');
124	                })->exists();
125	                if (!$ok) {
126	                    $courseId = \App\Models\ClassModel::where('id', $classId)->value('course_id');
127	                    $ok = $courseId && $user->permissionScopes()->where('course_id', $courseId)->exists();
128	                }
129	                if (!$ok) {
130	                    throw new \App\Common\Exceptions\BusinessRuleException('You are not enrolled in the specified class.');
131	                }
132	            }
133	
134	            $reservation = ReservationRequest::create([
135	                'user_id' => $user->id,
136	                'resource_id' => $data['resource_id'],
137	                'venue_id' => $data['venue_id'] ?? null,
138	                'venue_time_slot_id' => $data['venue_time_slot_id'] ?? null,
139	                'reservation_type' => $data['reservation_type'],
140	                'status' => 'pending',
141	                'start_date' => $startDate,
142	                'end_date' => $endDate,
143	                'notes' => $data['notes'] ?? null,
144	                'idempotency_key' => $data['idempotency_key'],
145	                'class_id' => $classId,
146	                'assignment_id' => $assignmentId,
147	            ]);
148	
149	            // Mark the slot as occupied
150	            if ($data['reservation_type'] === 'venue') {
151	                $slot->update(['reserved_by_reservation_id' => $reservation->id]);
152	            }
153	
154	            AuditLog::create([
155	                'user_id' => $user->id,
156	                'action' => 'reservation_created',
157	                'auditable_type' => ReservationRequest::class,
158	                'auditable_id' => $reservation->id,
159	            ]);
160	
161	            return $reservation;
162	        });
163	    }
164	
165	    public function approveReservation(ReservationRequest $reservation, User $approver, string $status, ?string $reason = null): ReservationRequest
166	    {
167	        return DB::transaction(function () use ($reservation, $approver, $status, $reason) {
168	            $reservation = ReservationRequest::whereKey($reservation->id)->lockForUpdate()->firstOrFail();
169	
170	            if ($reservation->status !== 'pending') {
171	                throw new \App\Common\Exceptions\BusinessRuleException('Can only act on pending reservations.');
172	            }
173	
174	            if ($status === 'rejected' && $reservation->reservation_type === 'venue' && $reservation->venue_time_slot_id) {
175	                // Release the slot
176	                VenueTimeSlot::where('id', $reservation->venue_time_slot_id)
177	                    ->where('reserved_by_reservation_id', $reservation->id)
178	                    ->update(['reserved_by_reservation_id' => null]);
179	            }
180	
181	            $reservation->update(['status' => $status]);
182	
183	            $reservation->approval()->create([
184	                'approved_by' => $approver->id,
185	                'status' => $status,
186	                'reason' => $reason,
187	            ]);
188	
189	            AuditLog::create([
190	                'user_id' => $approver->id,
191	                'action' => "reservation_{$status}",
192	                'auditable_type' => ReservationRequest::class,
193	                'auditable_id' => $reservation->id,
194	            ]);
195	
196	            Log::channel('operations')->info("Reservation {$status}", [
197	                'reservation_id' => $reservation->id, 'approver_id' => $approver->id,
198	            ]);
199	
200	            return $reservation->fresh();
201	        });
202	    }
203	
204	    public function cancelReservation(ReservationRequest $reservation, User $user): ReservationRequest
205	    {
206	        return DB::transaction(function () use ($reservation, $user) {
207	            $reservation = ReservationRequest::whereKey($reservation->id)->lockForUpdate()->firstOrFail();
208	
209	            if (!in_array($reservation->status, ['pending', 'approved'])) {
210	                throw new \App\Common\Exceptions\BusinessRuleException('Cannot cancel a reservation in this state.');
211	            }
212	
213	            // Release the venue time slot if applicable
214	            if ($reservation->reservation_type === 'venue' && $reservation->venue_time_slot_id) {
215	                VenueTimeSlot::where('id', $reservation->venue_time_slot_id)
216	                    ->where('reserved_by_reservation_id', $reservation->id)
217	                    ->update(['reserved_by_reservation_id' => null]);
218	            }
219	
220	            $reservation->update(['status' => 'cancelled']);
221	
222	            AuditLog::create([
223	                'user_id' => $user->id,
224	                'action' => 'reservation_cancelled',
225	                'auditable_type' => ReservationRequest::class,
226	                'auditable_id' => $reservation->id,
227	            ]);
228	
229	            return $reservation->fresh();
230	        });
231	    }
232	}
