17	    public function createLoanRequest(User $user, array $data): LoanRequest
18	    {
19	        return DB::transaction(function () use ($user, $data) {
20	            // Check allowlist/blacklist
21	            $resource = \App\Models\Resource::findOrFail($data['resource_id']);
22	            $accessCheck = $this->availability->checkUserResourceAccess($user, $resource);
23	            if (!$accessCheck['allowed']) {
24	                throw new \App\Common\Exceptions\BusinessRuleException($accessCheck['reason']);
25	            }
26	
27	            // Only equipment resources can be loaned
28	            if ($resource->resource_type !== 'equipment') {
29	                throw new \App\Common\Exceptions\BusinessRuleException(
30	                    'Only equipment resources can be requested for loan. Use reservations for venues or membership for entitlement packages.'
31	                );
32	            }
33	
34	            // Check user limits
35	            $check = $this->availability->canUserBorrow($user, $data['quantity'] ?? 1);
36	            if (!$check['allowed']) {
37	                throw new \App\Common\Exceptions\BusinessRuleException($check['reason']);
38	            }
39	
40	            // Find a lot with sufficient available quantity across all lots for this resource
41	            $requestedQty = $data['quantity'] ?? 1;
42	            $lots = InventoryLot::where('resource_id', $data['resource_id'])
43	                ->lockForUpdate()
44	                ->get();
45	
46	            if ($lots->isEmpty()) {
47	                throw new \App\Common\Exceptions\BusinessRuleException('No inventory available for this resource.');
48	            }
49	
50	            // Pick the first lot that can fulfill the request
51	            $lot = null;
52	            foreach ($lots as $candidate) {
53	                if ($this->availability->getLotAvailableQuantity($candidate) >= $requestedQty) {
54	                    $lot = $candidate;
55	                    break;
56	                }
57	            }
58	
59	            if (!$lot) {
60	                // Calculate total available across all lots for the error message
61	                $totalAvailable = $lots->sum(fn($l) => $this->availability->getLotAvailableQuantity($l));
62	                throw new \App\Common\Exceptions\BusinessRuleException(
63	                    "Insufficient inventory. Available: {$totalAvailable}, Requested: {$requestedQty}"
64	                );
65	            }
66	
67	            // Require class context if the student has class/course scopes
68	            // (ensures scoped staff can see and approve the request)
69	            $classId = $data['class_id'] ?? null;
70	            $assignmentId = $data['assignment_id'] ?? null;
71	
72	            if (!$classId && !$assignmentId) {
73	                $hasScopes = $user->permissionScopes()
74	                    ->where(function ($q) {
75	                        $q->whereNotNull('class_id')
76	                          ->orWhereNotNull('course_id');
77	                    })->exists();
78	                if ($hasScopes) {
79	                    throw new \App\Common\Exceptions\BusinessRuleException(
80	                        'Please select a class for this request so it can be routed to the appropriate staff for approval.'
81	                    );
82	                }
83	            }
84	
85	            if ($classId) {
86	                $hasClassScope = $user->permissionScopes()
87	                    ->where(function ($q) use ($classId) {
88	                        $q->where('class_id', $classId)
89	                          ->orWhere('scope_type', 'full');
90	                    })->exists();
91	                // Also allow if user has course scope covering this class
92	                if (!$hasClassScope) {
93	                    $courseId = \App\Models\ClassModel::where('id', $classId)->value('course_id');
94	                    $hasClassScope = $courseId && $user->permissionScopes()->where('course_id', $courseId)->exists();
95	                }
96	                if (!$hasClassScope) {
97	                    throw new \App\Common\Exceptions\BusinessRuleException('You are not enrolled in the specified class.');
98	                }
99	            }
100	
101	            if ($assignmentId) {
102	                $assignment = \App\Models\Assignment::find($assignmentId);
103	                if ($assignment) {
104	                    $hasAssignmentScope = $user->permissionScopes()
105	                        ->where(function ($q) use ($assignmentId, $assignment) {
106	                            $q->where('assignment_id', $assignmentId)
107	                              ->orWhere('class_id', $assignment->class_id)
108	                              ->orWhere('scope_type', 'full');
109	                        })->exists();
110	                    if (!$hasAssignmentScope) {
111	                        $courseId = \App\Models\ClassModel::where('id', $assignment->class_id)->value('course_id');
112	                        $hasAssignmentScope = $courseId && $user->permissionScopes()->where('course_id', $courseId)->exists();
113	                    }
114	                    if (!$hasAssignmentScope) {
115	                        throw new \App\Common\Exceptions\BusinessRuleException('You are not enrolled in the class for this assignment.');
116	                    }
117	                }
118	            }
119	
120	            $loanRequest = LoanRequest::create([
121	                'user_id' => $user->id,
122	                'resource_id' => $data['resource_id'],
123	                'inventory_lot_id' => $lot->id,
124	                'quantity' => $requestedQty,
125	                'status' => 'pending',
126	                'requested_at' => now(),
127	                'notes' => $data['notes'] ?? null,
128	                'idempotency_key' => $data['idempotency_key'],
129	                'class_id' => $classId,
130	                'assignment_id' => $assignmentId,
131	            ]);
132	
133	            AuditLog::create([
134	                'user_id' => $user->id,
135	                'action' => 'loan_request_created',
136	                'auditable_type' => LoanRequest::class,
137	                'auditable_id' => $loanRequest->id,
138	            ]);
139	
140	            return $loanRequest;
141	        });
142	    }
